// Flashlight directions:
// 0 - right, 1 - left, 2 - up, 3 - down
// 4 - right up, 5 - right down, 6 - left up, 7 - left down
int flashlight_dir = 0;
int flashlight_dir_prev = 0;
int flashlight_dir_prev_prev = 0;

// main program
int main(void) {
  volatile int *pixel_ctrl_ptr = (int *)0xFF203020;
  precompute_filled_circle();
  // Set up buffers
  *(pixel_ctrl_ptr + 1) = (int)&Buffer1;
  wait_for_vsync();
  pixel_buffer_start = *pixel_ctrl_ptr;
  clear_screen();

  *(pixel_ctrl_ptr + 1) = (int)&Buffer2;
  pixel_buffer_start = *(pixel_ctrl_ptr + 1);
  clear_screen();

  while (1) {
    // Show start screen
    if (!character_swap) {
      for (int i = 0; i < 240; i++) {
        for (int j = 0; j < 320; j++) {
          unsigned short color = start_screen[i * 320 + j];
          plot_pixel(j, i, color);
        }
      }
      wait_for_vsync();
      while (1) {
        read_PS2();
        if (key_enter) {  // Start game
          break;
        }
      }
      // reset score if new game
      player1_score = 0;
      prev_player1_score = 0;
      player2_score = 0;
      prev_player2_score = 0;
    }

    if (reset) {  // Reset game
      reset = false;
      continue;
    }

    // Initialize variables
    if (character_swap) {  // if is round to swap character
      thief_x = 50, thief_y = 50;
      thief_x_prev = 50, thief_y_prev = 50;
      thief_x_prev_prev = 50, thief_y_prev_prev = 50;
      thief_key_right = 0, thief_key_left = 0, thief_key_up = 0,
      thief_key_down = 0;
      skip_thief_frame = false;

      guard_x = 270 - GUARD_SIZE, guard_y = 190 - GUARD_SIZE;
      guard_x_prev = 270 - GUARD_SIZE, guard_y_prev = 190 - GUARD_SIZE;
      guard_x_prev_prev = 270 - GUARD_SIZE,
      guard_y_prev_prev = 190 - GUARD_SIZE;
      guard_key_right = 0, guard_key_left = 0, guard_key_up = 0,
      guard_key_down = 0;
      thief_caught = false;

      flashlight_dir = 1;  // point in left
      flashlight_dir_prev = 1;
      flashlight_dir_prev_prev = 1;

      timeCountdown = 30;
    } else {
      thief_x = 270 - THIEF_SIZE, thief_y = 190 - THIEF_SIZE;
      thief_x_prev = 270 - THIEF_SIZE, thief_y_prev = 190 - THIEF_SIZE;
      thief_x_prev_prev = 270 - THIEF_SIZE,
      thief_y_prev_prev = 190 - THIEF_SIZE;
      thief_key_right = 0, thief_key_left = 0, thief_key_up = 0,
      thief_key_down = 0;
      skip_thief_frame = false;

      guard_x = 50, guard_y = 50;
      guard_x_prev = 50, guard_y_prev = 50;
      guard_x_prev_prev = 50, guard_y_prev_prev = 50;
      guard_key_right = 0, guard_key_left = 0, guard_key_up = 0,
      guard_key_down = 0;
      thief_caught = false;

      flashlight_dir = 0;
      flashlight_dir_prev = 0;
      flashlight_dir_prev_prev = 0;

      timeCountdown = 30;
    }

    // Set up game elements
    bool game_running = true;
    timer_setup();

    // Switch to game background
    clear_screen();
    wait_for_vsync();
    pixel_buffer_start = *(pixel_ctrl_ptr + 1);

    while (game_running) {
      // Erase previous two positions
      draw_flashlight(guard_x_prev_prev, guard_y_prev_prev,
                      flashlight_dir_prev_prev, BACKGROUND_COLOR);
      draw_flashlight(guard_x_prev, guard_y_prev, flashlight_dir_prev,
                      BACKGROUND_COLOR);

      erase_thief(thief_x_prev_prev, thief_y_prev_prev);
      erase_thief(thief_x_prev, thief_y_prev);

      erase_guard(guard_x_prev_prev, guard_y_prev_prev);
      erase_guard(guard_x_prev, guard_y_prev);
      erase_picked_coin();

      // Get PS2 keyboard input
      read_PS2();

      // Check if thief gets caught
      thief_caught = check_thief_caught();

      // Check if esc is pressed or thief gets caught
      if (key_esc || thief_caught) {  // Reset game
        if (key_esc) {                // reset character swap
          character_swap = false;
        }
        if (thief_caught) {  // do character swap
          if (character_swap) {
            game_end = true;
          }
          character_swap = !character_swap;
        }
        clear_screen();
        wait_for_vsync();
        pixel_buffer_start = *(pixel_ctrl_ptr + 1);  // Refresh screen

        // Erase all the coins and reset timeCountdown and lastSpawnTime
        reset_coins();
        timeCountdown = 30;
        game_running = false;
        break;
      }

      // Update positions
      update_thief_position();
      update_guard_position();
      update_score();
      audio_update();
      // Draw new positions & coins
      draw_flashlight(guard_x, guard_y, flashlight_dir, FLASHLIGHT_COLOR);
      put_random_coin();
      draw_thief(thief_x, thief_y);
      draw_guard(guard_x, guard_y);

      // Draw background
      // timer counts down
      if ((*(timer_ptr) & 0b1) == 1) {
        *(timer_ptr) = 0;
        last_sec = timeCountdown;
        timeCountdown--;
      }

      // draw background elements
      draw_bg();
      draw_timer();

      draw_score();

      if (timeCountdown < 0) {
        *(timer_ptr + 1) = 0x8;
        if (character_swap) {
          game_end = true;
        }
        character_swap = !character_swap;
        clear_screen();
        wait_for_vsync();
        pixel_buffer_start = *(pixel_ctrl_ptr + 1);  // Refresh screen
        reset_coins();
        timeCountdown = 30;
        game_running = false;
        break;
      }

      // Refresh screen
      wait_for_vsync();
      pixel_buffer_start = *(pixel_ctrl_ptr + 1);
    }
    // ending screen
    if (game_end) {
      if (player1_score > player2_score) {  // Player1 wins
        for (int i = 0; i < 240; i++) {
          for (int j = 0; j < 320; j++) {
            unsigned short color = player1_wins[i * 320 + j];
            plot_pixel(j, i, color);
          }
        }
        audio_playback_mono(victory_sound_samples, victory_sound_samples_n, 1,
                            1);
      } else if (player1_score < player2_score) {  // Player2 wins
        for (int i = 0; i < 240; i++) {
          for (int j = 0; j < 320; j++) {
            unsigned short color = player2_wins[i * 320 + j];
            plot_pixel(j, i, color);
          }
        }
        audio_playback_mono(victory_sound_samples, victory_sound_samples_n, 1,
                            1);
      } else {  // Tie
        for (int i = 0; i < 240; i++) {
          for (int j = 0; j < 320; j++) {
            unsigned short color = tie_screen[i * 320 + j];
            plot_pixel(j, i, color);
          }
        }
        audio_playback_mono(victory_sound_samples, victory_sound_samples_n, 1,
                            1);
      }
      wait_for_vsync();
      pixel_buffer_start = *(pixel_ctrl_ptr + 1);

      // Wait until esc is pressed to reset
      while (1) {
        read_PS2();
        if (key_esc) {  // Back to start screen
          game_end = false;
          clear_screen();
          wait_for_vsync();
          pixel_buffer_start = *(pixel_ctrl_ptr + 1);
          break;
        }
      }
    }
  }
}

// ---------------------------- VGA functions ----------------------------
void plot_pixel(int x, int y, short int color) {
  volatile short int *pixel_addr;
  pixel_addr =
      (volatile short int *)(pixel_buffer_start + (y << 10) + (x << 1));
  *pixel_addr = color;
}

void clear_screen() {
  for (int x = 0; x < SCREEN_WIDTH; x++) {
    for (int y = 0; y < SCREEN_HEIGHT; y++) {
      plot_pixel(x, y, BACKGROUND_COLOR);
    }
  }
}

void wait_for_vsync() {
  volatile int *pixel_ctrl_ptr = (int *)0xFF203020;
  int status;
  *pixel_ctrl_ptr = 1;  // Signal refresh
  status = *(pixel_ctrl_ptr + 3);
  while ((status & 0x01) != 0) {
    status = *(pixel_ctrl_ptr + 3);
  }
}

void swap(int *a, int *b) {
  int temp = *a;
  *a = *b;
  *b = temp;
}

void draw_filled_triangle(int x0, int y0, int x1, int y1, int x2, int y2,
                          short int color) {
  // Sort vertices by y-coordinate (y0 <= y1 <= y2)
  if (y1 < y0) {
    swap(&x0, &x1);
    swap(&y0, &y1);
  }
  if (y2 < y0) {
    swap(&x0, &x2);
    swap(&y0, &y2);
  }
  if (y2 < y1) {
    swap(&x1, &x2);
    swap(&y1, &y2);
  }

  // Handle horizontal lines
  if (y0 == y2) {
    int min_x = min(x0, min(x1, x2));
    int max_x = max(x0, max(x1, x2));
    for (int x = min_x; x <= max_x; x++) {
      plot_pixel(x, y0, color);
    }
    return;
  }

  // Calculate long edge interpolation at y1
  int dy_total = y2 - y0;
  int x_mid = dy_total != 0 ? x0 + (x2 - x0) * (y1 - y0) / dy_total : x0;

  // Draw lower triangle (y0 to y1)
  if (y0 != y1) {
    for (int y = y0; y <= y1; y++) {
      int progress = y - y0;
      int left = x0 + (x1 - x0) * progress / (y1 - y0);
      int right = x0 + (x_mid - x0) * progress / (y1 - y0);
      if (left > right) {
        swap(&left, &right);
      }
      for (int x = left; x <= right; x++) {
        plot_pixel(x, y, color);
      }
    }
  }

  // Draw upper triangle (y1 to y2)
  if (y1 != y2) {
    for (int y = y1; y <= y2; y++) {
      int progress = y - y1;
      int left = x1 + (x2 - x1) * progress / (y2 - y1);
      int right = x_mid + (x2 - x_mid) * progress / (y2 - y1);
      if (left > right) {
        swap(&left, &right);
      }
      for (int x = left; x <= right; x++) {
        plot_pixel(x, y, color);
      }
    }
  }
}

// ---------------------------- PS2 function ----------------------------
void read_PS2() {
  volatile int *PS2_ptr = (int *)0xFF200100;  // PS2 base address
  int PS2_data, RVALID;

  while (1) {  // check all pending inputs
    PS2_data = *PS2_ptr;
    RVALID =
        (PS2_data & 0x8000) >> 15;  // Get RVALID to check if there is new code
    if (!RVALID) {                  // Exit if no more data
      break;
    }

    unsigned char code = PS2_data & 0xFF;  // Get scan code
    if (code == 0xE0) {                    // If it is arrow scan code
      extended = 1;
      continue;
    } else if (code == 0xF0) {
      break_code = 1;
      continue;
    }

    // Process key code
    if (extended) {          // Thief's arrow keys
      if (break_code) {      // Release
        if (code == 0x74) {  // right arrow
          thief_key_right = 0;
        } else if (code == 0x6B) {  // left arrow
          thief_key_left = 0;
        } else if (code == 0x75) {  // up arrow
          thief_key_up = 0;
        } else if (code == 0x72) {  // down arrow
          thief_key_down = 0;
        }
      } else {               // Press
        if (code == 0x74) {  // right arrow
          thief_key_right = 1;
        } else if (code == 0x6B) {  // left arrow
          thief_key_left = 1;
        } else if (code == 0x75) {  // up arrow
          thief_key_up = 1;
        } else if (code == 0x72) {  // down arrow
          thief_key_down = 1;
        }
      }
      extended = 0;
      break_code = 0;
    } else {                 // Guard's WASD keys and ENTER/ESC
      if (break_code) {      // Release
        if (code == 0x23) {  // D right
          guard_key_right = 0;
        } else if (code == 0x1C) {  // A left
          guard_key_left = 0;
        } else if (code == 0x1D) {  // W up
          guard_key_up = 0;
        } else if (code == 0x1B) {  // S down
          guard_key_down = 0;
        } else if (code == 0x5A) {  // Enter
          key_enter = 0;
        } else if (code == 0x76) {  // Esc
          key_esc = 0;
        }
      } else {               // Press
        if (code == 0x23) {  // D right
          guard_key_right = 1;
        } else if (code == 0x1C) {  // A left
          guard_key_left = 1;
        } else if (code == 0x1D) {  // W up
          guard_key_up = 1;
        } else if (code == 0x1B) {  // S down
          guard_key_down = 1;
        } else if (code == 0x5A) {  // Enter
          key_enter = 1;
        } else if (code == 0x76) {  // Esc
          key_esc = 1;
        }
      }
      break_code = 0;
    }
  }
}

// ---------------------------- Thief functions ----------------------------
void draw_thief(int x, int y) {
  for (int i = 0; i < THIEF_SIZE; i++) {
    for (int j = 0; j < THIEF_SIZE; j++) {
      if (thief_pixels[j][i] != 1) {
        if (thief_isBack) {
          plot_pixel(x + i, y + j, thief_back_pixels[j][i]);
        } else {
          plot_pixel(x + i, y + j, thief_pixels[j][i]);
        }
      }
    }
  }
}

void erase_thief(int x, int y) {
  for (int i = 0; i < THIEF_SIZE; i++) {
    for (int j = 0; j < THIEF_SIZE; j++) {
      if (thief_pixels[j][i] != 1) {
        plot_pixel(x + i, y + j, BACKGROUND_COLOR);
      }
    }
  }
}

void update_thief_position() {
  int cx = guard_x + GUARD_SIZE / 2;
  int cy = guard_y + GUARD_SIZE / 2;
  int x1, y1, x2, y2;

  // Gets the guard current flashlight boundary
  if (flashlight_dir == 0) {  // Right
    x1 = cx + 50;
    y1 = cy - 12;
    x2 = cx + 50;
    y2 = cy + 12;
  } else if (flashlight_dir == 1) {  // Left
    x1 = cx - 50;
    y1 = cy - 12;
    x2 = cx - 50;
    y2 = cy + 12;
  } else if (flashlight_dir == 2) {  // Up
    x1 = cx - 12;
    y1 = cy - 50;
    x2 = cx + 12;
    y2 = cy - 50;
  } else if (flashlight_dir == 3) {  // Down
    x1 = cx - 12;
    y1 = cy + 50;
    x2 = cx + 12;
    y2 = cy + 50;
  } else if (flashlight_dir == 4) {
    x1 = cx + 27;
    y1 = cy - 43;
    x2 = cx + 43;
    y2 = cy - 27;
  } else if (flashlight_dir == 5) {  // Right-Down
    x1 = cx + 27;
    y1 = cy + 43;
    x2 = cx + 43;
    y2 = cy + 27;
  } else if (flashlight_dir == 6) {  // Left-Up
    x1 = cx - 27;
    y1 = cy - 43;
    x2 = cx - 43;
    y2 = cy - 27;
  } else {  // Left-Down
    x1 = cx - 27;
    y1 = cy + 43;
    x2 = cx - 43;
    y2 = cy + 27;
  }

  // Check flashlight coordinates respect to screen boundaries
  x1 = max(0, min(x1, SCREEN_WIDTH - 1));
  y1 = max(TOP_BOARDER_LINE_POS + 1, min(y1, BOTTOM_BOARDER_LINE_POS - 1));
  x2 = max(0, min(x2, SCREEN_WIDTH - 1));
  y2 = max(TOP_BOARDER_LINE_POS + 1, min(y2, BOTTOM_BOARDER_LINE_POS - 1));

  // Check if inside flashlight
  bool in_flashlight =
      is_point_in_triangle(thief_x + THIEF_SIZE / 2, thief_y + THIEF_SIZE / 2,
                           cx, cy, x1, y1, x2, y2);

  // Handle frame skipping for speed reduction
  if (in_flashlight) {
    skip_thief_frame = !skip_thief_frame;
    if (skip_thief_frame) {
      // Skip movement this frame
      return;
    }
  } else {
    skip_thief_frame = false;
  }

  // Save previous positions
  thief_x_prev_prev = thief_x_prev;
  thief_y_prev_prev = thief_y_prev;

  thief_x_prev = thief_x;
  thief_y_prev = thief_y;

  // Update current position
  if (character_swap) {
    if (guard_key_right) {  // D Right
      thief_x += THIEF_SPEED;
    }
    if (guard_key_left) {  // A Left
      thief_x += -THIEF_SPEED;
    }
    if (guard_key_up) {  // W Up
      thief_y += -THIEF_SPEED;
      thief_isBack = true;
    }
    if (guard_key_down) {  // S Down
      thief_y += THIEF_SPEED;
      thief_isBack = false;
    }
  } else {
    if (thief_key_right) {  // Right Arrow
      thief_x += THIEF_SPEED;
    }
    if (thief_key_left) {  // Left Arrow
      thief_x += -THIEF_SPEED;
    }
    if (thief_key_up) {  // Up Arrow
      thief_y += -THIEF_SPEED;
      thief_isBack = true;
    }
    if (thief_key_down) {  // Down Arrow
      thief_y += THIEF_SPEED;
      thief_isBack = false;
    }
  }

  // Prevent moving out of bounds
  if (thief_x < 0) {
    thief_x = 0;
  }
  if (thief_x > SCREEN_WIDTH - THIEF_SIZE) {
    thief_x = SCREEN_WIDTH - THIEF_SIZE;
  }
  if (thief_y < TOP_BOARDER_LINE_POS + 1) {
    thief_y = TOP_BOARDER_LINE_POS + 1;
  }
  if (thief_y > BOTTOM_BOARDER_LINE_POS - THIEF_SIZE) {
    thief_y = BOTTOM_BOARDER_LINE_POS - THIEF_SIZE;
  }

  for (int i = 0; i < 3; i++) {
    if (isCircleSquareColliding(circle_pos_x[i], SCREEN_HEIGHT / 2, CIRCLE_RAD,
                                thief_x, thief_y)) {
      thief_x = thief_x_prev;
      thief_y = thief_y_prev;
    }
  }
}

bool is_point_in_triangle(int px, int py, int x0, int y0, int x1, int y1,
                          int x2, int y2) {
  // Calculate vectors
  int s = (x0 - x2) * (py - y2) - (y0 - y2) * (px - x2);
  int t = (x1 - x0) * (py - y0) - (y1 - y0) * (px - x0);
  int u = (x2 - x1) * (py - y1) - (y2 - y1) * (px - x1);

  // Check if all same sign -> inside triangle
  return ((s < 0) == (t < 0)) && ((t < 0) == (u < 0));
}

// ---------------------------- Guard functions ----------------------------
void draw_guard(int x, int y) {
  for (int i = 0; i < GUARD_SIZE; i++) {
    for (int j = 0; j < GUARD_SIZE; j++) {
      if (guard_pixels[j][i] != 1) {
        if (guard_isBack) {
          plot_pixel(x + i, y + j, guard_back_pixels[j][i]);
        } else {
          plot_pixel(x + i, y + j, guard_pixels[j][i]);
        }
      }
    }
  }
}

void erase_guard(int x, int y) {
  for (int i = 0; i < GUARD_SIZE; i++) {
    for (int j = 0; j < GUARD_SIZE; j++) {
      if (guard_pixels[j][i] != 1) {
        plot_pixel(x + i, y + j, BACKGROUND_COLOR);
      }
    }
  }
}

void update_guard_position() {
  // Save previous positions and flashlight directions
  guard_x_prev_prev = guard_x_prev;
  guard_y_prev_prev = guard_y_prev;
  flashlight_dir_prev_prev = flashlight_dir_prev;

  guard_x_prev = guard_x;
  guard_y_prev = guard_y;
  flashlight_dir_prev = flashlight_dir;

  // Update current position and flashlight directions
  if (character_swap) {
    if (thief_key_right) {  // D right
      guard_x += GUARD_SPEED;
      flashlight_dir = 0;
    }
    if (thief_key_left) {  // A left
      guard_x += -GUARD_SPEED;
      flashlight_dir = 1;
    }
    if (thief_key_up) {  // W up
      guard_y += -GUARD_SPEED;
      flashlight_dir = 2;
      guard_isBack = true;
    }
    if (thief_key_down) {  // S down
      guard_y += GUARD_SPEED;
      flashlight_dir = 3;
      guard_isBack = false;
    }
    if (thief_key_right && thief_key_up) {  // right up
      flashlight_dir = 4;
    }
    if (thief_key_right && thief_key_down) {  // right down
      flashlight_dir = 5;
    }
    if (thief_key_left && thief_key_up) {  // left up
      flashlight_dir = 6;
    }
    if (thief_key_left && thief_key_down) {  // left down
      flashlight_dir = 7;
    }
  } else {
    if (guard_key_right) {  // D right
      guard_x += GUARD_SPEED;
      flashlight_dir = 0;
    }
    if (guard_key_left) {  // A left
      guard_x += -GUARD_SPEED;
      flashlight_dir = 1;
    }
    if (guard_key_up) {  // W up
      guard_y += -GUARD_SPEED;
      flashlight_dir = 2;
      guard_isBack = true;
    }
    if (guard_key_down) {  // S down
      guard_y += GUARD_SPEED;
      flashlight_dir = 3;
      guard_isBack = false;
    }
    if (guard_key_right && guard_key_up) {  // right up
      flashlight_dir = 4;
    }
    if (guard_key_right && guard_key_down) {  // right down
      flashlight_dir = 5;
    }
    if (guard_key_left && guard_key_up) {  // left up
      flashlight_dir = 6;
    }
    if (guard_key_left && guard_key_down) {  // left down
      flashlight_dir = 7;
    }
  }

  // Prevent moving out of bounds
  if (guard_x < 0) {
    guard_x = 0;
  }
  if (guard_x > SCREEN_WIDTH - GUARD_SIZE) {
    guard_x = SCREEN_WIDTH - GUARD_SIZE;
  }
  if (guard_y < TOP_BOARDER_LINE_POS + 1) {
    guard_y = TOP_BOARDER_LINE_POS + 1;
  }
  if (guard_y > BOTTOM_BOARDER_LINE_POS - GUARD_SIZE) {
    guard_y = BOTTOM_BOARDER_LINE_POS - GUARD_SIZE;
  }

  for (int i = 0; i < 3; i++) {
    if (isCircleSquareColliding(circle_pos_x[i], SCREEN_HEIGHT / 2, CIRCLE_RAD,
                                guard_x, guard_y)) {
      guard_x = guard_x_prev;
      guard_y = guard_y_prev;
    }
  }
}

void draw_flashlight(int x, int y, int dir, short int color) {
  int cx = x + GUARD_SIZE / 2;
  int cy = y + GUARD_SIZE / 2;
  int x1, y1, x2, y2;

  // Calculate offset coordinates
  if (dir == 0) {  // Right
    x1 = cx + 50;
    y1 = cy - 12;
    x2 = cx + 50;
    y2 = cy + 12;
  } else if (dir == 1) {  // Left
    x1 = cx - 50;
    y1 = cy - 12;
    x2 = cx - 50;
    y2 = cy + 12;
  } else if (dir == 2) {  // Up
    x1 = cx - 12;
    y1 = cy - 50;
    x2 = cx + 12;
    y2 = cy - 50;
  } else if (dir == 3) {  // Down
    x1 = cx - 12;
    y1 = cy + 50;
    x2 = cx + 12;
    y2 = cy + 50;
  } else if (dir == 4) {
    x1 = cx + 27;
    y1 = cy - 43;
    x2 = cx + 43;
    y2 = cy - 27;
  } else if (dir == 5) {  // Right-Down
    x1 = cx + 27;
    y1 = cy + 43;
    x2 = cx + 43;
    y2 = cy + 27;
  } else if (dir == 6) {  // Left-Up
    x1 = cx - 27;
    y1 = cy - 43;
    x2 = cx - 43;
    y2 = cy - 27;
  } else {  // Left-Down
    x1 = cx - 27;
    y1 = cy + 43;
    x2 = cx - 43;
    y2 = cy + 27;
  }

  // Check all coordinates to screen boundaries
  x1 = max(0, min(x1, SCREEN_WIDTH - 1));
  y1 = max(TOP_BOARDER_LINE_POS + 1, min(y1, BOTTOM_BOARDER_LINE_POS - 1));
  x2 = max(0, min(x2, SCREEN_WIDTH - 1));
  y2 = max(TOP_BOARDER_LINE_POS + 1, min(y2, BOTTOM_BOARDER_LINE_POS - 1));

  if (!(x1 == x2 && y1 == y2)) {  // avoid drawing line
    draw_filled_triangle(cx, cy, x1, y1, x2, y2, color);
  }
}

bool check_thief_caught() {
  // Calculate bounding boxes
  int guard_left = guard_x;
  int guard_right = guard_x + GUARD_SIZE;
  int guard_top = guard_y;
  int guard_bottom = guard_y + GUARD_SIZE;

  int thief_left = thief_x;
  int thief_right = thief_x + THIEF_SIZE;
  int thief_top = thief_y;
  int thief_bottom = thief_y + THIEF_SIZE;

  // Check for overlap
  return (guard_left < thief_right) && (guard_right > thief_left) &&
         (guard_top < thief_bottom) && (guard_bottom > thief_top);
}

// ------------------------- Background setup/drawing functions
// -------------------------
void timer_setup() {
  uint32_t countdown = (uint32_t)CLOCK_FREQ;  // Countdown for 1 seconds
  *(timer_ptr + 2) = countdown;
  *(timer_ptr + 3) = countdown >> 16;
  *(timer_ptr + 1) = 0b0110;
  *(timer_ptr) = 0;
}

void draw_bg() {
  draw_filled_circle(SCREEN_WIDTH / 2, SCREEN_HEIGHT / 2,
                     GREY);  // Center circle
  draw_filled_circle(SCREEN_WIDTH / 6, SCREEN_HEIGHT / 2,
                     GREY);  // Left circle
  draw_filled_circle(5 * SCREEN_WIDTH / 6, SCREEN_HEIGHT / 2, GREY);
  //   draw_circle(SCREEN_WIDTH / 2, SCREEN_HEIGHT / 2, CIRCLE_RAD, 0xffff);
  //   draw_circle(SCREEN_WIDTH / 6, SCREEN_HEIGHT / 2, CIRCLE_RAD, 0xffff);
  //   draw_circle(5 * SCREEN_WIDTH / 6, SCREEN_HEIGHT / 2, CIRCLE_RAD,
  //               0xffff);  // Distance between the circle around 76
  draw_line(0, TOP_BOARDER_LINE_POS, SCREEN_WIDTH - 1, TOP_BOARDER_LINE_POS,
            GREY);
  draw_line(0, BOTTOM_BOARDER_LINE_POS, SCREEN_WIDTH - 1,
            BOTTOM_BOARDER_LINE_POS, GREY);

  // Draw P1 and P2
  draw_letter_P(45, 220, WHITE);
  draw_digit(52, 220, 1, YELLOW);

  draw_letter_P(260, 220, WHITE);
  draw_digit(267, 220, 2, YELLOW);

  // Draw Score
  draw_score_label(140, 5, WHITE);
}

void draw_timer() {
  int prev_digit1 = last_sec / 10;
  int prev_digit2 = last_sec % 10;

  // if timeCountdown >= 10, draw 2 digits
  // Otherwise, draw only one digit
  //   draw_digit(SCREEN_WIDTH / 2 - 3, SCREEN_HEIGHT / 2 - 3, last_sec, 0);

  draw_digit(SCREEN_WIDTH / 2 - 3, SCREEN_HEIGHT / 2 - 3, last_sec, GREY);
  if (timeCountdown >= 10) {
    // draw_digit(SCREEN_WIDTH / 2 - 7, SCREEN_HEIGHT / 2 - 3, prev_digit1, 0);
    // draw_digit(SCREEN_WIDTH / 2 + 1, SCREEN_HEIGHT / 2 - 3, prev_digit2, 0);

    draw_digit(SCREEN_WIDTH / 2 - 7, SCREEN_HEIGHT / 2 - 3, prev_digit1, GREY);
    draw_digit(SCREEN_WIDTH / 2 + 1, SCREEN_HEIGHT / 2 - 3, prev_digit2, GREY);
    draw_digit(SCREEN_WIDTH / 2 - 7, SCREEN_HEIGHT / 2 - 3, timeCountdown / 10,
               0x07e0);
    draw_digit(SCREEN_WIDTH / 2 + 1, SCREEN_HEIGHT / 2 - 3, timeCountdown % 10,
               0x07e0);
  } else if (timeCountdown == 9) {
    // draw_digit(SCREEN_WIDTH / 2 - 7, SCREEN_HEIGHT / 2 - 3, prev_digit1, 0);
    // draw_digit(SCREEN_WIDTH / 2 + 1, SCREEN_HEIGHT / 2 - 3, prev_digit2, 0);

    draw_digit(SCREEN_WIDTH / 2 - 7, SCREEN_HEIGHT / 2 - 3, prev_digit1, GREY);
    draw_digit(SCREEN_WIDTH / 2 + 1, SCREEN_HEIGHT / 2 - 3, prev_digit2, GREY);
    draw_digit(SCREEN_WIDTH / 2 - 3, SCREEN_HEIGHT / 2 - 3, timeCountdown,
               0x07e0);
    prev_digit1 = timeCountdown;
  } else {
    // draw_digit(SCREEN_WIDTH / 2 - 3, SCREEN_HEIGHT / 2 - 3, last_sec, 0);

    draw_digit(SCREEN_WIDTH / 2 - 3, SCREEN_HEIGHT / 2 - 3, last_sec, GREY);
    draw_digit(SCREEN_WIDTH / 2 - 3, SCREEN_HEIGHT / 2 - 3, timeCountdown,
               0x07e0);
  }
}

void draw_digit(int x, int y, int digit, short int color) {
  for (int row = 0; row < DIGIT_HEIGHT; row++) {
    for (int col = 0; col < DIGIT_WIDTH; col++) {
      // Check if the bit corresponding to the current pixel is set.
      if (digit_font[digit][row] & (0x80 >> col)) {
        plot_pixel(x + col, y + row, color);
      }
    }
  }
}

void draw_letter_P(int x, int y, short int color) {
  // Dimensions for the letter P
  int width = 5;
  int height = 8;
  int thickness = 2;

  // Vertical backbone
  for (int i = 0; i < height; i++) {
    for (int t = 0; t < thickness; t++) {
      plot_pixel(x + t, y + i, color);
    }
  }

  // Top horizontal bar
  for (int i = 0; i < width; i++) {
    for (int t = 0; t < thickness; t++) {
      plot_pixel(x + i, y + t, color);
    }
  }

  // Middle horizontal bar
  for (int i = 0; i < width; i++) {
    for (int t = 0; t < thickness; t++) {
      plot_pixel(x + i, y + 4 + t, color);
    }
  }

  // Right vertical bar (top half only)
  for (int i = 1; i < 4; i++) {
    for (int t = 0; t < thickness; t++) {
      plot_pixel(x + width - 1 + t, y + i, color);
    }
  }
}

void draw_S(int x, int y, short int color) {
  for (int i = 0; i < 7; i++) plot_pixel(x + i, y, color);
  for (int i = 1; i < 4; i++) plot_pixel(x, y + i, color);
  for (int i = 0; i < 7; i++) plot_pixel(x + i, y + 4, color);
  for (int i = 5; i < 8; i++) plot_pixel(x + 6, y + i, color);
  for (int i = 0; i < 7; i++) plot_pixel(x + i, y + 8, color);
}

void draw_C(int x, int y, short int color) {
  for (int i = 0; i < 7; i++) plot_pixel(x + i, y, color);
  for (int i = 1; i < 8; i++) plot_pixel(x, y + i, color);
  for (int i = 0; i < 7; i++) plot_pixel(x + i, y + 8, color);
}

void draw_O(int x, int y, short int color) {
  for (int i = 0; i < 7; i++) plot_pixel(x + i, y, color);
  for (int i = 1; i < 8; i++) {
    plot_pixel(x, y + i, color);
    plot_pixel(x + 6, y + i, color);
  }
  for (int i = 0; i < 7; i++) plot_pixel(x + i, y + 8, color);
}

void draw_R(int x, int y, short int color) {
  // Top horizontal bar (full width)
  for (int i = 0; i < 7; i++) plot_pixel(x + i, y, color);

  // Left vertical bar
  for (int i = 1; i < 9; i++) plot_pixel(x, y + i, color);

  // Right vertical bar (top half only)
  for (int i = 1; i < 4; i++) plot_pixel(x + 6, y + i, color);

  // Middle horizontal bar
  for (int i = 1; i < 6; i++) plot_pixel(x + i, y + 4, color);

  // Diagonal leg from center to bottom right
  plot_pixel(x + 3, y + 5, color);
  plot_pixel(x + 4, y + 6, color);
  plot_pixel(x + 5, y + 7, color);
  plot_pixel(x + 6, y + 8, color);
}

void draw_E(int x, int y, short int color) {
  for (int i = 0; i < 7; i++) plot_pixel(x + i, y, color);
  for (int i = 1; i < 8; i++) plot_pixel(x, y + i, color);
  for (int i = 0; i < 5; i++) plot_pixel(x + i, y + 4, color);
  for (int i = 0; i < 7; i++) plot_pixel(x + i, y + 8, color);
}

void draw_score_label(int x, int y, short int color) {
  draw_S(x + 0, y, color);
  draw_C(x + 8, y, color);
  draw_O(x + 16, y, color);
  draw_R(x + 24, y, color);
  draw_E(x + 32, y, color);
}

// ------------------------- Shape drawing functions -------------------------
void draw_line(int x0, int y0, int x1, int y1, short int colour) {
  bool is_steep = abs(y1 - y0) > abs(x1 - x0);
  if (is_steep) {
    swap(&x0, &y0);
    swap(&x1, &y1);
  }

  if (x0 > x1) {
    swap(&x0, &x1);
    swap(&y0, &y1);
  }

  int deltax = x1 - x0;
  int deltay = abs(y1 - y0);
  int error = -1 * (deltax / 2);
  int y = y0;
  int y_step = (y0 < y1) ? 1 : -1;

  for (int x = x0; x <= x1;
       x++)  // draw_line(150, 150, 319, 0, 0x07E0);  x0 = 150, deltax = 169
  {
    if (is_steep) {
      plot_pixel(y, x, colour);
    } else {
      plot_pixel(x, y, colour);
    }

    error += deltay;
    if (error > 0) {
      y += y_step;
      error -= deltax;
    }
  }
}

void draw_circle(int xc, int yc, int radius, short int colour) {
  int x = 0, y = radius;
  int d = 3 - 2 * radius;  // Decision variable for the midpoint algorithm
  while (x <= y) {
    // Draw the eight symmetrical points.
    plot_pixel(xc + x, yc + y, colour);
    plot_pixel(xc - x, yc + y, colour);
    plot_pixel(xc + x, yc - y, colour);
    plot_pixel(xc - x, yc - y, colour);
    plot_pixel(xc + y, yc + x, colour);
    plot_pixel(xc - y, yc + x, colour);
    plot_pixel(xc + y, yc - x, colour);
    plot_pixel(xc - y, yc - x, colour);

    if (d < 0) {
      d = d + 4 * x + 6;
    } else {
      d = d + 4 * (x - y) + 10;
      y--;
    }
    x++;
  }
}

void precompute_filled_circle() {
  for (int y = -CIRCLE_RAD; y <= CIRCLE_RAD; y++) {
    for (int x = -CIRCLE_RAD; x <= CIRCLE_RAD; x++) {
      if (x * x + y * y <= CIRCLE_RAD * CIRCLE_RAD) {
        circle_pixels[num_circle_pixels].x_offset = x;
        circle_pixels[num_circle_pixels].y_offset = y;
        num_circle_pixels++;
      }
    }
  }
}

void draw_filled_circle(int xc, int yc, short int colour) {
  for (int i = 0; i < num_circle_pixels; i++) {
    int x = xc + circle_pixels[i].x_offset;
    int y = yc + circle_pixels[i].y_offset;
    if (x >= 0 && x < SCREEN_WIDTH && y >= 0 && y < SCREEN_HEIGHT) {
      plot_pixel(x, y, colour);
    }
  }
}

// ------------------------- Draw coins/Update score -------------------------
void update_score() {
  int sx = thief_x, sy = thief_y;
  for (int i = 0; i < 10; i++) {
    int cx = coin_x[i], cy = coin_y[i];
    if (cx == -1) continue;
    if (isCircleSquareColliding(cx, cy, COIN_RAD, sx, sy)) {
    //   audio_playback_mono(pickedCoins_sound_samples,
    //                       pickedCoins_sound_samples_n, 1, 1);
    audio_play_stream(pickedCoins_sound_samples, pickedCoins_sound_samples_n);
      picked_coin_x[i] = coin_x[i];
      picked_coin_y[i] = coin_y[i];
      coin_x[i] = -1, coin_y[i] = -1;
      prev_player1_score = player1_score;
      prev_player2_score = player2_score;
      if (character_swap) {
        player1_score++;
      } else {
        player2_score++;
      }
      break;
    }
  }
}

void draw_coin(int x, int y, int rad, int color) {
  draw_circle(x, y, rad, color);
  draw_circle(x, y, 2, color);
}

void draw_score() {
  draw_digit(SCREEN_WIDTH / 2 - 18, TOP_BOARDER_LINE_POS - 10,
             prev_player1_score,
             0);  // draw a sample blue 0 at the top
  draw_digit(SCREEN_WIDTH / 2 + 10, TOP_BOARDER_LINE_POS - 10,
             prev_player2_score,
             0);  // draw a sample red 0 at the top
  draw_digit(SCREEN_WIDTH / 2 - 18, TOP_BOARDER_LINE_POS - 10, player1_score,
             0xffff);  // draw a sample blue 0 at the top
  draw_digit(SCREEN_WIDTH / 2 + 10, TOP_BOARDER_LINE_POS - 10, player2_score,
             0xffff);  // draw a sample red 0 at the top
}

void put_random_coin() {
  // rand() % (upper_bound - lower_bound + 1) + lower_bound;
  int circle_y = SCREEN_HEIGHT / 2;
  int is_collide;

  if (coin_num >= 10) {
    coin_num = 0;  // Reset when full (could shift instead if desired)
  }

  if (timeCountdown % 3 == 0 && timeCountdown != lastSpawnTime &&
      timeCountdown != 0) {
    for (int i = coin_num; i < coin_num + 1; i++) {
      prev_coin_x[i] = coin_x[i];
      prev_coin_y[i] = coin_y[i];

      coin_x[i] = rand() % SCREEN_WIDTH;
      coin_y[i] = rand() % (BOTTOM_BOARDER_LINE_POS - TOP_BOARDER_LINE_POS) +
                  TOP_BOARDER_LINE_POS;

      for (int j = 0; j < 3; j++) {
        is_collide =
            areCirclesColliding(coin_x[i], coin_y[i], COIN_RAD, circle_pos_x[j],
                                circle_y, CIRCLE_RAD) ||
            boarderColliding(coin_x[i], coin_y[i], COIN_RAD);
        while (is_collide) {
          coin_x[i] = rand() % SCREEN_WIDTH;
          coin_y[i] =
              rand() % (BOTTOM_BOARDER_LINE_POS - TOP_BOARDER_LINE_POS) +
              TOP_BOARDER_LINE_POS;
          is_collide =
              areCirclesColliding(coin_x[i], coin_y[i], COIN_RAD,
                                  circle_pos_x[j], circle_y, CIRCLE_RAD) ||
              boarderColliding(coin_x[i], coin_y[i], COIN_RAD);
        }
      }
    }
    coin_num++;
    lastSpawnTime = timeCountdown;
  }

  // Draw the current coin if it exists
  for (int i = 0; i < coin_num; i++) {
    if (coin_x[i] != -1 && coin_y[i] != -1) {
      draw_coin(coin_x[i], coin_y[i], COIN_RAD, 0xfea0);  // Gold coin
    }
  }
}

void reset_coins() {
  for (int i = 0; i < 10; i++) {
    erase_coin(coin_x[i], coin_y[i], COIN_RAD);
    coin_x[i] = -1;
    coin_y[i] = -1;
    picked_coin_x[i] = -1;
    picked_coin_y[i] = -1;
  }
  coin_num = 0;
  lastSpawnTime = 30;
}

void erase_picked_coin() {
  for (int i = 0; i < 10; i++) {
    erase_coin(picked_coin_x[i], picked_coin_y[i], COIN_RAD);
  }
}

void erase_coin(int x, int y, int rad) {
  if (x != -1 && y != -1) {
    // Erase by drawing a black circle over the old coin
    draw_coin(x, y, rad, 0);  // Assuming black background
  }
}

// --------------------------- Shape Collision Detect Function
// --------------------------- Collision detection between a circle and an
// axis-aligned square Circle: center (cx, cy) and radius r Square: top-left
// (sx, sy) with side length
int isCircleSquareColliding(int cx, int cy, int r, int sx, int sy) {
  // Find the closest point on the square to the circle center.
  int closestX = min(max(cx, sx), sx + THIEF_SIZE - 1);
  int closestY = min(max(cy, sy), sy + THIEF_SIZE - 1);

  // Compute the distance between the circle's center and this closest point.
  int dx = cx - closestX;
  int dy = cy - closestY;

  // Check if the distance squared is less than or equal to the radius squared.
  return (dx * dx + dy * dy) <= (r * r);
}

int areCirclesColliding(int c1_x, int c1_y, int r1, int c2_x, int c2_y,
                        int r2) {
  int dx = c1_x - c2_x;
  int dy = c1_y - c2_y;
  int rSum = r1 + r2;
  return (dx * dx + dy * dy) <= (rSum * rSum);
}

int boarderColliding(int x, int y, int radius) {
  if (x - radius <= 0) {
    return 1;
  }
  if (x + radius >= SCREEN_WIDTH) {
    return 1;
  }

  if (y - radius <= TOP_BOARDER_LINE_POS) {
    return 1;
  }
  if (y + radius >= BOTTOM_BOARDER_LINE_POS) {
    return 1;
  }
  return 0;
}

void audio_playback_mono(int *samples, int n, int step, int replicate) {
  int i;

  audiop->control = 0x8;  // clear the output FIFOs
  audiop->control = 0x0;  // resume input conversion
  for (i = 0; i < n; i += step) {
    // output data if there is space in the output FIFOs
    for (int r = 0; r < replicate; r++) {
      while (audiop->warc == 0);
      audiop->ldata = samples[i];
      audiop->rdata = samples[i];
    }
  }
}


void audio_play_stream(int *samples, int length) {
    current_sample = samples;
    sample_length = length;
    sample_position = 0;
    is_playing = 1;
    audiop->control = 0x8;  // Clear FIFO
    audiop->control = 0x0;  // Resume conversion
}


void audio_update() {
    if (!is_playing) return;

    // Fill the buffer while there's space in the audio FIFO
    while (audiop->warc > 0 && sample_position < sample_length) {
        int chunk_size = min(AUDIO_BUFFER_SIZE, sample_length - sample_position);
        
        // Copy a chunk of the sample to the buffer
        for (int i = 0; i < chunk_size; i++) {
            audio_buffer[i] = current_sample[sample_position + i];
        }

        // Write to audio hardware
        for (int i = 0; i < chunk_size; i++) {
            audiop->ldata = audio_buffer[i];
            audiop->rdata = audio_buffer[i];
        }

        sample_position += chunk_size;
    }

    // Stop when the sample ends
    if (sample_position >= sample_length) {
        is_playing = 0;
    }
}
